mapper.select:
SELECT sll.username, sll.login_ip, sll.browser, sll.os, sll.result_msg, sll.status, sll.create_time FROM sys_login_log sll WHERE sll.enabled = '1'
AND sll.username LIKE CONCAT(#{req.username},'%')
AND sll.status = #{req.status}
AND sll.create_time BETWEEN #{req.startTime} AND #{req.endTime}
${req.dataScopeSql}
ORDER BY sll.id DESC

SELECT sll.username, sll.login_ip, sll.browser, sll.os, sll.result_msg, sll.status, sll.create_time FROM sys_login_log sll WHERE sll.enabled = '1'
AND sll.username LIKE CONCAT(#{req.username},'%')
AND sll.status = #{req.status}
AND sll.create_time BETWEEN TO_DATE(#{req.startTime}, 'yyyy-mm-dd hh24:mi:ss') AND TO_DATE(#{req.endTime}, 'yyyy-mm-dd hh24:mi:ss')
${req.dataScopeSql}
ORDER BY sll.id DESC
